#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub enum MaterialIconKey {
    CalendarToday,
    Check,
    Close,
    ChevronBackward,
    ChevronForward,
    Edit,
    Menu,
    ArrowBack,
    ArrowRight,
    ArrowDropDown,
    ArrowDropUp,
    Remove,
    Schedule,
    Keyboard,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct MaterialIconSpec {
    pub property_name: &'static str,
    pub asset_name: &'static str,
    pub svg: &'static str,
}

#[must_use]
pub fn material_icon(key: MaterialIconKey) -> MaterialIconSpec {
    MaterialIconRegistry::new().icon(key)
}

#[must_use]
pub fn from_slint_property_name(property_name: &str) -> Option<MaterialIconSpec> {
    MaterialIconRegistry::new().from_property_name(property_name)
}

#[derive(Debug, Clone, Copy, Default)]
pub struct MaterialIconRegistry;

impl MaterialIconRegistry {
    #[must_use]
    pub const fn new() -> Self {
        Self
    }

    #[must_use]
    pub fn icon(self, key: MaterialIconKey) -> MaterialIconSpec {
        match key {
            MaterialIconKey::CalendarToday => material_icon_spec("calendar_today", "CalendarToday"),
            MaterialIconKey::Check => material_icon_spec("check", "Check"),
            MaterialIconKey::Close => material_icon_spec("close", "Close"),
            MaterialIconKey::ChevronBackward => {
                material_icon_spec("chevron_backward", "ChevronLeft")
            }
            MaterialIconKey::ChevronForward => {
                material_icon_spec("chevron_forward", "ChevronRight")
            }
            MaterialIconKey::Edit => material_icon_spec("edit", "Pen"),
            MaterialIconKey::Menu => material_icon_spec("menu", "Menu"),
            MaterialIconKey::ArrowBack => material_icon_spec("arrow_back", "ArrowLeft"),
            MaterialIconKey::ArrowRight => material_icon_spec("arrow_right", "ArrowRight"),
            MaterialIconKey::ArrowDropDown => material_icon_spec("arrow_drop_down", "ArrowDown"),
            MaterialIconKey::ArrowDropUp => material_icon_spec("arrow_drop_up", "ArrowUp"),
            MaterialIconKey::Remove => material_icon_spec("remove", "Minus"),
            MaterialIconKey::Schedule => material_icon_spec("schedule", "Clock"),
            MaterialIconKey::Keyboard => material_icon_spec("keyboard", "Keyboard"),
        }
    }

    #[must_use]
    pub fn from_property_name(self, property_name: &str) -> Option<MaterialIconSpec> {
        let key = match property_name {
            "calendar_today" => MaterialIconKey::CalendarToday,
            "check" => MaterialIconKey::Check,
            "close" => MaterialIconKey::Close,
            "chevron_backward" => MaterialIconKey::ChevronBackward,
            "chevron_forward" => MaterialIconKey::ChevronForward,
            "edit" => MaterialIconKey::Edit,
            "menu" => MaterialIconKey::Menu,
            "arrow_back" => MaterialIconKey::ArrowBack,
            "arrow_right" => MaterialIconKey::ArrowRight,
            "arrow_drop_down" => MaterialIconKey::ArrowDropDown,
            "arrow_drop_up" => MaterialIconKey::ArrowDropUp,
            "remove" => MaterialIconKey::Remove,
            "schedule" => MaterialIconKey::Schedule,
            "keyboard" => MaterialIconKey::Keyboard,
            _ => return None,
        };
        Some(self.icon(key))
    }
}

