#[derive(Debug, Clone, Copy, Default)]
pub struct UiIconRegistry;

impl UiIconRegistry {
    #[must_use]
    pub const fn new() -> Self {
        Self
    }

    #[must_use]
    pub fn icon(self, key: UiIconKey) -> UiIconSpec {
        match key {
            UiIconKey::FloorResetViewport => ui_icon_spec("home", "Home"),
            UiIconKey::FloorOpenSvgOverlay => ui_icon_spec("image", "Svg"),
            UiIconKey::NavOpen => ui_icon_spec("menu", "Menu"),
            UiIconKey::NavClose => ui_icon_spec("close", "Close"),
            UiIconKey::NavSettings => ui_icon_spec("edit", "Pen"),
            UiIconKey::AudioOpenPanel => ui_icon_spec("play_circle", "PlayCircle"),
            UiIconKey::AudioPlay => ui_icon_spec("play_arrow", "Play"),
            UiIconKey::AudioPause => ui_icon_spec("pause", "Pause"),
            UiIconKey::AudioLink => ui_icon_spec("link", "Link"),
            UiIconKey::ScenesAddBefore => ui_icon_spec("add_row_above", "TableRowPlusBefore"),
            UiIconKey::ScenesAddAfter => ui_icon_spec("add_row_below", "TableRowPlusAfter"),
            UiIconKey::ScenesDelete => ui_icon_spec("delete", "Delete"),
            UiIconKey::ScenesOpenChoreography => ui_icon_spec("folder_open", "FolderOpen"),
            UiIconKey::ScenesSaveChoreography => ui_icon_spec("save", "ContentSave"),
            UiIconKey::ScenesNavigateSettings => ui_icon_spec("settings", "Cog"),
            UiIconKey::ScenesNavigateDancers => ui_icon_spec("groups", "AccountGroup"),
            UiIconKey::SettingsNavigateBack => ui_icon_spec("arrow_back", "ArrowLeft"),
            UiIconKey::DancersAdd => ui_icon_spec("group_add", "AccountMultiplePlus"),
            UiIconKey::DancersRemove => ui_icon_spec("group_remove", "AccountMultipleMinus"),
            UiIconKey::NumberPickerDecrement => ui_icon_spec("remove", "Minus"),
            UiIconKey::NumberPickerIncrement => ui_icon_spec("add", "Plus"),
        }
    }

    #[must_use]
    pub fn from_slint_name(self, slint_name: &str) -> Option<UiIconSpec> {
        let key = match slint_name {
            "Home" => UiIconKey::FloorResetViewport,
            "Svg" => UiIconKey::FloorOpenSvgOverlay,
            "Menu" => UiIconKey::NavOpen,
            "Close" => UiIconKey::NavClose,
            "Pen" => UiIconKey::NavSettings,
            "PlayCircle" => UiIconKey::AudioOpenPanel,
            "Play" => UiIconKey::AudioPlay,
            "Pause" => UiIconKey::AudioPause,
            "Link" => UiIconKey::AudioLink,
            "TableRowPlusBefore" => UiIconKey::ScenesAddBefore,
            "TableRowPlusAfter" => UiIconKey::ScenesAddAfter,
            "Delete" => UiIconKey::ScenesDelete,
            "FolderOpen" => UiIconKey::ScenesOpenChoreography,
            "ContentSave" => UiIconKey::ScenesSaveChoreography,
            "Cog" => UiIconKey::ScenesNavigateSettings,
            "AccountGroup" => UiIconKey::ScenesNavigateDancers,
            "ArrowLeft" => UiIconKey::SettingsNavigateBack,
            "AccountMultiplePlus" => UiIconKey::DancersAdd,
            "AccountMultipleMinus" => UiIconKey::DancersRemove,
            "AccountMultipleRemove" => UiIconKey::DancersRemove,
            "Minus" => UiIconKey::NumberPickerDecrement,
            "Plus" => UiIconKey::NumberPickerIncrement,
            _ => return None,
        };
        Some(self.icon(key))
    }
}

#[must_use]
pub fn from_slint_name(slint_name: &str) -> Option<UiIconSpec> {
    UiIconRegistry::new().from_slint_name(slint_name)
}

fn material_icon_spec(property_name: &'static str, asset_name: &'static str) -> MaterialIconSpec {
    MaterialIconSpec {
        property_name,
        asset_name,
        svg: must_asset_icon_data(asset_name).svg,
    }
}

fn ui_icon_spec(token: &'static str, slint_name: &'static str) -> UiIconSpec {
    UiIconSpec {
        token,
        slint_name,
        svg: must_asset_icon_data(slint_name).svg,
    }
}

fn must_asset_icon_data(name: &str) -> MaterialAssetIcon {
    asset_icon(name).unwrap_or_else(|| panic!("missing material asset icon: {name}"))
}

#[cfg(test)]
mod tests {
    use super::ALL_ASSET_ICON_KEYS;
    use super::ALL_ASSET_ICONS;
    use super::MaterialIconKey;
    use super::UiIconKey;
    use super::UiIconRegistry;
    use super::asset_icon_by_key;
    use super::asset_icon_count;
    use super::asset_icon_key;
    use super::from_slint_property_name;
    use super::material_icon;

    #[test]
    fn asset_icon_key_registry_covers_every_catalog_entry() {
        assert_eq!(ALL_ASSET_ICON_KEYS.len(), ALL_ASSET_ICONS.len());
        assert_eq!(ALL_ASSET_ICON_KEYS.len(), asset_icon_count());
        for key in ALL_ASSET_ICON_KEYS {
            let icon = asset_icon_by_key(*key);
            assert!(icon.svg.contains("<svg"));
            assert_eq!(asset_icon_key(icon.name), Some(*key));
        }
    }

    #[test]
    fn legacy_material_icon_registry_resolves_expected_slint_properties() {
        let cases = [
            (
                MaterialIconKey::CalendarToday,
                "calendar_today",
                "CalendarToday",
            ),
            (MaterialIconKey::Check, "check", "Check"),
            (MaterialIconKey::Close, "close", "Close"),
            (
                MaterialIconKey::ChevronBackward,
                "chevron_backward",
                "ChevronLeft",
            ),
            (
                MaterialIconKey::ChevronForward,
                "chevron_forward",
                "ChevronRight",
            ),
            (MaterialIconKey::Edit, "edit", "Pen"),
            (MaterialIconKey::Menu, "menu", "Menu"),
            (MaterialIconKey::ArrowBack, "arrow_back", "ArrowLeft"),
            (MaterialIconKey::ArrowRight, "arrow_right", "ArrowRight"),
            (
                MaterialIconKey::ArrowDropDown,
                "arrow_drop_down",
                "ArrowDown",
            ),
            (MaterialIconKey::ArrowDropUp, "arrow_drop_up", "ArrowUp"),
            (MaterialIconKey::Remove, "remove", "Minus"),
            (MaterialIconKey::Schedule, "schedule", "Clock"),
            (MaterialIconKey::Keyboard, "keyboard", "Keyboard"),
        ];
        for (key, property_name, asset_name) in cases {
            let icon = material_icon(key);
            assert_eq!(icon.property_name, property_name);
            assert_eq!(icon.asset_name, asset_name);
            assert!(icon.svg.contains("<svg"));
            let resolved =
                from_slint_property_name(property_name).expect("slint property should resolve");
            assert_eq!(resolved, icon);
        }
        assert!(from_slint_property_name("does_not_exist").is_none());
    }

    #[test]
    fn ui_icon_registry_stays_backed_by_material_assets() {
        let cases = [
            (UiIconKey::FloorResetViewport, "home", "Home", "Home"),
            (UiIconKey::FloorOpenSvgOverlay, "image", "Svg", "Svg"),
            (UiIconKey::NavOpen, "menu", "Menu", "Menu"),
            (UiIconKey::NavClose, "close", "Close", "Close"),
            (UiIconKey::NavSettings, "edit", "Pen", "Pen"),
            (
                UiIconKey::AudioOpenPanel,
                "play_circle",
                "PlayCircle",
                "PlayCircle",
            ),
            (UiIconKey::AudioPlay, "play_arrow", "Play", "Play"),
            (UiIconKey::AudioPause, "pause", "Pause", "Pause"),
            (UiIconKey::AudioLink, "link", "Link", "Link"),
            (
                UiIconKey::ScenesAddBefore,
                "add_row_above",
                "TableRowPlusBefore",
                "TableRowPlusBefore",
            ),
            (
                UiIconKey::ScenesAddAfter,
                "add_row_below",
                "TableRowPlusAfter",
                "TableRowPlusAfter",
            ),
            (UiIconKey::ScenesDelete, "delete", "Delete", "Delete"),
            (
                UiIconKey::ScenesOpenChoreography,
                "folder_open",
                "FolderOpen",
                "FolderOpen",
            ),
            (
                UiIconKey::ScenesSaveChoreography,
                "save",
                "ContentSave",
                "ContentSave",
            ),
            (UiIconKey::ScenesNavigateSettings, "settings", "Cog", "Cog"),
            (
                UiIconKey::ScenesNavigateDancers,
                "groups",
                "AccountGroup",
                "AccountGroup",
            ),
            (
                UiIconKey::SettingsNavigateBack,
                "arrow_back",
                "ArrowLeft",
                "ArrowLeft",
            ),
            (
                UiIconKey::DancersAdd,
                "group_add",
                "AccountMultiplePlus",
                "AccountMultiplePlus",
            ),
            (
                UiIconKey::DancersRemove,
                "group_remove",
                "AccountMultipleMinus",
                "AccountMultipleMinus",
            ),
            (UiIconKey::NumberPickerDecrement, "remove", "Minus", "Minus"),
            (UiIconKey::NumberPickerIncrement, "add", "Plus", "Plus"),
        ];
        for (key, token, slint_name, asset_name) in cases {
            let icon = UiIconRegistry::new().icon(key);
            assert_eq!(icon.token, token);
            assert_eq!(icon.slint_name, slint_name);
            assert_eq!(
                super::asset_icon_key(asset_name)
                    .map(asset_icon_by_key)
                    .map(|it| it.svg),
                Some(icon.svg)
            );
        }
    }
}
